void ApplyMigrations(AppDbContext db)
{
    // Migrate() manages its own transaction per migration internally.
    // Do not wrap it in BeginTransaction() — EF Core 9 throws if a
    // user transaction is already open when Migrate() is called.
    db.Database.Migrate();
}

